Button:
[ M3e.button [ M3e.variantTonal ] [ M3e.slotIcon (M3e.icon [ M3e.attrName "send" ] []), M3e.slotDefault (Kit.text "Send") ]
    , M3e.button [ M3e.variantTonal ] [ M3e.slotTrailingIcon (M3e.icon [ M3e.attrName "open_in_new_window" ] []), M3e.slotDefault (Kit.text "Open") ]
    ]

[ M3e.button [ M3e.variantFilled, M3e.attrDisabled True ] [ M3e.slotDefault (Kit.text "Disabled") ]
    , M3e.button [ M3e.variantFilled, M3e.attrDisabledInteractive True ] [ M3e.slotDefault (Kit.text "Disabled Interactive") ]
    ]

Chips:
[ M3e.assistChip [] [ M3e.slotDefault (Kit.text "Outlined Assist") ]
    , M3e.assistChip [ M3e.variantElevated ] [ M3e.slotDefault (Kit.text "Elevated Assist") ]
    ]

[ M3e.assistChip [ M3e.attrDisabled True ] [ M3e.slotDefault (Kit.text "Disabled") ]
    , M3e.assistChip [ M3e.attrDisabledInteractive True ] [ M3e.slotDefault (Kit.text "Disabled Interactive") ]
    ]

[ M3e.filterChipSet [ M3e.ariaLabel "Filter by topic", M3e.attrHideSelectionIndicator True ] (M3e.FilterChipSet.children [ M3e.filterChip [] [ M3e.slotDefault (Kit.text "Design") ], M3e.filterChip [] [ M3e.slotDefault (Kit.text "Accessibility") ], M3e.filterChip [] [ M3e.slotIcon (M3e.icon [ M3e.attrName "motion_photos_on" ] []), M3e.slotDefault (Kit.text "Motion") ], M3e.filterChip [] [ M3e.slotIcon (M3e.icon [ M3e.attrName "description" ] []), M3e.slotDefault (Kit.text "Documentation") ] ])
    , Kit.text ">"
    ]

[ M3e.suggestionChip [] [ M3e.slotDefault (Kit.text "Outlined Suggestion") ]
    , M3e.suggestionChip [ M3e.variantElevated ] [ M3e.slotDefault (Kit.text "Elevated Suggestion") ]
    ]

[ M3e.suggestionChip [ M3e.attrDisabled True ] [ M3e.slotDefault (Kit.text "Disabled") ]
    , M3e.suggestionChip [ M3e.attrDisabledInteractive True ] [ M3e.slotDefault (Kit.text "Disabled Interactive") ]
    ]

Fab:
[ M3e.fab [ M3e.attrDisabled True ] [ M3e.slotDefault (M3e.icon [ M3e.attrName "add" ] []) ]
    , M3e.fab [ M3e.attrDisabledInteractive True ] [ M3e.slotDefault (M3e.icon [ M3e.attrName "add" ] []) ]
    ]

IconButton:
[ M3e.iconButton [ M3e.variantTonal, M3e.widthNarrow ] [ M3e.slotDefault (M3e.icon [ M3e.attrName "add" ] []) ]
    , M3e.iconButton [ M3e.variantTonal, M3e.widthWide ] [ M3e.slotDefault (M3e.icon [ M3e.attrName "add" ] []) ]
    ]

[ M3e.iconButton [ M3e.variantFilled, M3e.attrDisabled True ] [ M3e.slotDefault (M3e.icon [ M3e.attrName "check" ] []) ]
    , M3e.iconButton [ M3e.variantFilled, M3e.attrDisabledInteractive True ] [ M3e.slotDefault (M3e.icon [ M3e.attrName "check" ] []) ]
    ]

RadioGroup:
[ Native.node Html.label [] [ Kit.text "Select an option" ]
    , M3e.radioGroup [] [ M3e.slotDefault (Native.node Html.label [] [ M3e.radio [ M3e.attrValue "1" ] [], Kit.text "Option 1" ]) ]
    ]

[ Native.node Html.label [] [ Kit.text "Select an option" ]
    , M3e.radioGroup [] [ M3e.slotDefault (Native.node Html.label [] [ M3e.radio [ M3e.attrDisabled True, M3e.attrValue "1" ] [], Kit.text "Option 1" ]) ]
    ]

[ Native.node Html.label [] [ Kit.text "Select an option" ]
    , M3e.radioGroup [ M3e.attrDisabled True ] [ M3e.slotDefault (Native.node Html.label [] [ M3e.radio [ M3e.attrValue "1" ] [], Kit.text "Option 1" ]) ]
    ]

[ Native.node Html.label [] [ Kit.text "Select an option" ]
    , M3e.radioGroup [ M3e.attrRequired True ] [ M3e.slotDefault (Native.node Html.label [] [ M3e.radio [ M3e.attrValue "1" ] [], Kit.text "Option 1" ]) ]
    ]

Switch:
[ M3e.switch [ M3e.iconsSelected, M3e.attrChecked True ] []
    , M3e.switch [ M3e.iconsBoth ] []
    ]

Toolbar:
[ M3e.toolbar [ M3e.variantStandard ] (M3e.Toolbar.children [ M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.attrName "arrow_back" ] []) ], M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.attrName "arrow_forward" ] []) ], M3e.iconButton [ M3e.widthWide, M3e.variantFilled ] [ M3e.slotDefault (M3e.icon [ M3e.attrName "add" ] []) ], M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.attrName "picture_in_picture" ] []) ], M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.attrName "more_vert" ] []) ] ])
    , M3e.toolbar [ M3e.variantVibrant ] []
    ]

Tooltip:
[ M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.attrName "arrow_back" ] []) ]
    , M3e.tooltip [ M3e.attrFor "button" ] [ M3e.slotDefault (Kit.text "Go Back") ]
    ]

[ M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.attrName "arrow_back" ] []) ]
    , M3e.tooltip [ M3e.attrFor "button", M3e.attrShowDelay 0, M3e.attrHideDelay 200 ] [ M3e.slotDefault (Kit.text "Go Back") ]
    ]

[ M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.attrName "arrow_back" ] []) ]
    , M3e.tooltip [ M3e.attrFor "button", M3e.attrDisabled True ] [ M3e.slotDefault (Kit.text "Go Back") ]
    ]

[ M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.attrName "settings" ] []) ]
    , M3e.richTooltip [ M3e.attrFor "button" ] [ M3e.slotSubhead (Native.span [] [ Kit.text "New settings available" ]), M3e.slotDefault (Kit.text "Now you can adjust the uploaded image quality, and upgrade your available storage space.") ]
    ]
